'use server';
/**
 * @fileOverview A Genkit flow for generating AI-powered trading signals.
 *
 * - generateAISignal - A function that generates AI trading signals for various financial instruments.
 * - AISignalInput - The input type for the generateAISignal function.
 * - AISignalOutput - The return type for the generateAISignal function.
 */

import {ai} from '@/ai/genkit';
import {z} from 'genkit';

const AISignalInputSchema = z.object({
  instrumentType: z
    .enum(['Forex', 'Crypto'])
    .describe('The type of financial instrument (e.g., Forex, Crypto).'),
  instrumentName: z
    .string()
    .describe(
      'The name of the financial instrument (e.g., Gold, EUR/USD, BTC, ETH).'
    ),
});
export type AISignalInput = z.infer<typeof AISignalInputSchema>;

const AISignalOutputSchema = z.object({
  entryPrice: z.number().describe('The recommended entry price for the trade.'),
  takeProfit: z
    .number()
    .describe('The recommended take profit level for the trade.'),
  stopLoss: z
    .number()
    .describe('The recommended stop loss level for the trade.'),
  confidenceScore: z
    .number()
    .min(0)
    .max(100)
    .describe('An AI-calculated confidence score (0-100) for the signal.'),
  direction: z.enum(['Buy', 'Sell']).describe('The recommended trade direction.'),
  reasoning: z.string().describe('A brief explanation for the signal.'),
});
export type AISignalOutput = z.infer<typeof AISignalOutputSchema>;

export async function generateAISignal(
  input: AISignalInput
): Promise<AISignalOutput> {
  return aiSignalGenerationFlow(input);
}

const prompt = ai.definePrompt({
  name: 'aiSignalGenerationPrompt',
  input: {schema: AISignalInputSchema},
  output: {schema: AISignalOutputSchema},
  prompt: `You are an expert financial analyst providing trading signals.
Generate a Buy/Sell signal for the following financial instrument based on the HYPER-BULLISH MARKET OF APRIL 2026.

STRICT PRICE CONTEXT FOR APRIL 2026 (MANDATORY):
- Gold (XAUUSD): Currently trading between $4,500 and $4,850.
- Bitcoin (BTCUSD): Currently trading between $285,000 and $320,000.
- Ethereum (ETHUSD): Currently trading between $12,500 and $15,000.
- EUR/USD: Currently trading around 1.0550 - 1.0750.

Your response MUST use these 2026 price levels. Any price below $4000 for Gold or $200,000 for Bitcoin is WRONG for this simulation.

Instrument Type: {{{instrumentType}}}
Instrument Name: {{{instrumentName}}}`,
});

const aiSignalGenerationFlow = ai.defineFlow(
  {
    name: 'aiSignalGenerationFlow',
    inputSchema: AISignalInputSchema,
    outputSchema: AISignalOutputSchema,
  },
  async (input) => {
    const {output} = await prompt(input);
    return output!;
  }
);
